32		// Live phase overrides from workerProgress subscription (workerID -> phase)
33		let livePhaseOverrides = $state<Map<string, string>>(new Map());
34		let showStartForm = $state(false);
35		let starting = $state(false);
36		let stoppingId = $state<string | null>(null);
37		let actionError = $state<string | null>(null);
38		let harness = $state('');
39		let profile = $state('smart');
40		let effort = $state('medium');
41		let labelFilter = $state('');
42	
43		// Subscribe to progress events for all running workers
44		$effect(() => {
45			const runningIds = data.workers.edges
46				.filter((e) => e.node.state === 'running')
47				.map((e) => e.node.id);
48	
49			livePhaseOverrides = new Map();
50	
51			const disposes = runningIds.map((workerID) =>
52				subscribeWorkerProgress(workerID, (evt) => {
53					const next = new Map(livePhaseOverrides);
54					next.set(evt.workerID, evt.phase);
55					livePhaseOverrides = next;
56				})
57			);
58	
59			return () => disposes.forEach((d) => d());
60		});
61	
62		// The currently open worker (from child route params)
63		let activeWorker = $derived(($page.params as Record<string, string>)['workerId'] ?? null);
64	
65		function openWorker(workerId: string) {
66			const p = $page.params as Record<string, string>;
67			goto(`/nodes/${p['nodeId']}/projects/${p['projectId']}/workers/${workerId}`);
68		}
69	
70		function sessionsHref(): string {
71			const p = $page.params as Record<string, string>;
72			return `/nodes/${p['nodeId']}/projects/${p['projectId']}/sessions`;
73		}
74	
75		function errorText(err: unknown): string {
76			return err instanceof Error ? err.message : 'Worker action failed.';
77		}
78	
79		async function startWorker() {
80			actionError = null;
81			if (!profile.trim() || !effort.trim()) {
82				actionError = 'Profile and effort are required.';
83				return;
84			}
85			starting = true;
86			try {
87				const client = createClient(fetch);
88				await client.request(START_WORKER_MUTATION, {
89					input: {
90						projectId: data.projectId,
91						harness: harness.trim() || null,
92						profile: profile.trim(),
93						effort: effort.trim(),
94						labelFilter: labelFilter.trim() || null
95					}
96				});
97				showStartForm = false;
98				harness = '';
99				labelFilter = '';
100				await invalidateAll();
101			} catch (err) {
102				actionError = errorText(err);
103			} finally {
104				starting = false;
105			}
106		}
107	
108		async function stopWorker(event: MouseEvent, workerId: string) {
109			event.stopPropagation();
110			actionError = null;
111			if (!window.confirm(`Stop worker ${workerId}?`)) return;
112			stoppingId = workerId;
113			try {
114				const client = createClient(fetch);
115				await client.request(STOP_WORKER_MUTATION, { id: workerId });
116				await invalidateAll();
117			} catch (err) {
118				actionError = errorText(err);
119			} finally {
120				stoppingId = null;
121			}
122		}
123	
124		function stateClass(state: string): string {
125			switch (state) {
126				case 'running':
127					return 'text-green-600 dark:text-green-400';
128				case 'idle':
129					return 'text-blue-600 dark:text-blue-400';
130				case 'stopped':
131					return 'text-gray-500 dark:text-gray-400';
132				case 'error':
133					return 'text-red-600 dark:text-red-400';
134				default:
135					return 'text-gray-500 dark:text-gray-400';
136			}
137		}
