1	import type { LayoutLoad } from './$types'
2	import { createClient } from '$lib/gql/client'
3	import { gql } from 'graphql-request'
4	
5	const WORKERS_QUERY = gql`
6		query WorkersByProject($projectID: String!) {
7			workersByProject(projectID: $projectID, first: 50) {
8				edges {
9					node {
10						id
11						kind
12						state
13						status
14						harness
15						model
16						currentBead
17						attempts
18						successes
19						failures
20						startedAt
21					}
22					cursor
23				}
24				pageInfo {
25					hasNextPage
26					endCursor
27				}
28				totalCount
29			}
30		}
31	`
32	
33	interface WorkerNode {
34		id: string
35		kind: string
36		state: string
37		status: string | null
38		harness: string | null
39		model: string | null
40		currentBead: string | null
41		attempts: number | null
42		successes: number | null
43		failures: number | null
44		startedAt: string | null
45	}
46	
47	interface WorkerEdge {
48		node: WorkerNode
49		cursor: string
50	}
51	
52	interface WorkerConnection {
53		edges: WorkerEdge[]
54		pageInfo: { hasNextPage: boolean; endCursor: string | null }
55		totalCount: number
56	}
57	
58	interface WorkersResult {
59		workersByProject: WorkerConnection
60	}
61	
62	export const load: LayoutLoad = async ({ params, fetch }) => {
63		const client = createClient(fetch as unknown as typeof globalThis.fetch)
64		const data = await client.request<WorkersResult>(WORKERS_QUERY, {
65			projectID: params.projectId
66		})
67		return {
68			projectId: params.projectId,
69			workers: data.workersByProject
70		}
71	}
