102	/**
103	 * Set up GraphQL route mocking for the workers pages.
104	 */
105	async function mockGraphQL(page: import('@playwright/test').Page, workers = WORKERS) {
106		await page.route('/graphql', async (route) => {
107			const body = route.request().postDataJSON() as { query: string };
108	
109			if (body.query.includes('NodeInfo')) {
110				await route.fulfill({
111					status: 200,
112					contentType: 'application/json',
113					body: JSON.stringify({ data: { nodeInfo: NODE_INFO } })
114				});
115			} else if (body.query.includes('Projects')) {
116				await route.fulfill({
117					status: 200,
118					contentType: 'application/json',
119					body: JSON.stringify({
120						data: { projects: { edges: PROJECTS.map((p) => ({ node: p })) } }
121					})
122				});
123			} else if (body.query.includes('WorkersByProject')) {
124				await route.fulfill({
125					status: 200,
126					contentType: 'application/json',
127					body: JSON.stringify({ data: makeWorkersResponse(workers) })
128				});
129			} else if (body.query.includes('WorkerDetail')) {
130				await route.fulfill({
131					status: 200,
132					contentType: 'application/json',
133					body: JSON.stringify({ data: { worker: WORKER_DETAIL } })
134				});
135			} else if (body.query.includes('WorkerLog')) {
136				await route.fulfill({
137					status: 200,
138					contentType: 'application/json',
139					body: JSON.stringify({ data: { workerLog: WORKER_LOG } })
140				});
141			} else if (body.query.includes('AgentSessions') || body.query.includes('agentSessions')) {
142				await route.fulfill({
143					status: 200,
144					contentType: 'application/json',
145					body: JSON.stringify({ data: makeSessionsResponse() })
146				});
147			} else if (body.query.includes('WorkerProgress')) {
148				// Subscriptions are handled over WebSocket; pass through
149				await route.continue();
150			} else {
151				await route.continue();
152			}
153		});
154	}
