448	func DispatchPluginAction(workingDir string, name string, action string) (string, error) {
449		pluginActionMu.Lock()
450		defer pluginActionMu.Unlock()
451	
452		state, err := registry.LoadState()
453		if err != nil {
454			return "", fmt.Errorf("loading plugin state: %w", err)
455		}
456	
457		switch action {
458		case "install":
459			if entry := state.FindInstalled(name); entry != nil && entry.VerifyFiles() {
460				return "installed", nil
461			}
462			entry, err := installRegistryPlugin(workingDir, state, name)
463			if err != nil {
464				return "", err
465			}
466			if entry != nil && entry.VerifyFiles() {
467				return "installed", nil
468			}
469			return "", fmt.Errorf("plugin %q install completed but recorded files are not present", name)
470		case "update":
471			installed := state.FindInstalled(name)
472			if installed == nil {
473				return "", fmt.Errorf("plugin %q is not installed", name)
474			}
475			pkg, err := registry.BuiltinRegistry().Find(name)
476			if err != nil {
477				return "", fmt.Errorf("plugin %q is not updateable from the built-in registry", name)
478			}
479			if installed.Version == pkg.Version && installed.VerifyFiles() {
480				return "installed", nil
481			}
482			entry, err := installRegistryPlugin(workingDir, state, name)
483			if err != nil {
484				return "", err
485			}
486			if entry != nil && entry.VerifyFiles() {
487				return "installed", nil
488			}
489			return "", fmt.Errorf("plugin %q update completed but recorded files are not present", name)
490		case "uninstall":
491			entry := state.FindInstalled(name)
492			if entry == nil {
493				return "", fmt.Errorf("plugin %q is not installed", name)
494			}
495			if err := registry.UninstallPackage(entry); err != nil {
496				return "", err
497			}
498			state.Remove(name)
499			if err := registry.SaveState(state); err != nil {
500				return "", fmt.Errorf("saving plugin state: %w", err)
501			}
502			return "uninstalled", nil
503		default:
504			return "", fmt.Errorf("unsupported plugin action %q", action)
505		}
506	}
