508	func installRegistryPlugin(workingDir string, state *registry.InstalledState, name string) (*registry.InstalledEntry, error) {
509		pkg, err := registry.BuiltinRegistry().Find(name)
510		if err != nil {
511			return nil, err
512		}
513	
514		origDir, _ := os.Getwd()
515		if workingDir != "" && origDir != workingDir {
516			if err := os.Chdir(workingDir); err != nil {
517				return nil, fmt.Errorf("entering project root: %w", err)
518			}
519			defer func() { _ = os.Chdir(origDir) }()
520		}
521	
522		entry, err := registry.InstallPackage(pkg)
523		if err != nil {
524			return nil, fmt.Errorf("installing plugin %q: %w", name, err)
525		}
526		state.AddOrUpdate(entry)
527		if err := registry.SaveState(state); err != nil {
528			return nil, fmt.Errorf("saving plugin state: %w", err)
529		}
530		return state.FindInstalled(name), nil
531	}
