533	func readComparisonRecords(workingDir string) ([]comparisonDispatchRecord, error) {
534		dir := filepath.Join(workingDir, ".ddx", "comparisons")
535		entries, err := os.ReadDir(dir)
536		if os.IsNotExist(err) {
537			return []comparisonDispatchRecord{}, nil
538		}
539		if err != nil {
540			return nil, err
541		}
542		records := make([]comparisonDispatchRecord, 0, len(entries))
543		for _, entry := range entries {
544			if entry.IsDir() || filepath.Ext(entry.Name()) != ".json" {
545				continue
546			}
547			data, err := os.ReadFile(filepath.Join(dir, entry.Name()))
548			if err != nil {
549				return nil, err
550			}
551			var record comparisonDispatchRecord
552			if err := json.Unmarshal(data, &record); err != nil {
553				return nil, fmt.Errorf("parsing comparison record %s: %w", entry.Name(), err)
554			}
555			if record.ID == "" {
556				continue
557			}
558			records = append(records, record)
559		}
560		sort.Slice(records, func(i, j int) bool {
561			if !records[i].CreatedAt.Equal(records[j].CreatedAt) {
562				return records[i].CreatedAt.After(records[j].CreatedAt)
563			}
564			return records[i].ID < records[j].ID
565		})
566		return records, nil
567	}
