626		out := make([]*PluginInfo, 0, len(byName))
627		for _, info := range byName {
628			out = append(out, info)
629		}
630		sort.Slice(out, func(i, j int) bool { return out[i].Name < out[j].Name })
631		return out, nil
632	}
