678	func enrichPluginInfoFromDisk(info *PluginInfo, workingDir string, name string, entry registry.InstalledEntry) {
679		for _, root := range pluginRootCandidates(workingDir, name, entry) {
680			if root == "" {
681				continue
682			}
683			if stat, err := os.Stat(root); err != nil || !stat.IsDir() {
684				continue
685			}
686			if info.DiskBytes == 0 {
687				info.DiskBytes = dirSize(root)
688			}
689			if pkg, _, err := registry.LoadPackageManifest(root); err == nil && pkg != nil {
690				if pkg.Version != "" {
691					info.Version = pkg.Version
692				}
693				if pkg.Description != "" {
694					info.Description = pkg.Description
695				}
696				if pkg.Type != "" {
697					info.Type = string(pkg.Type)
698				}
699				if pkg.Source != "" {
700					info.RegistrySource = pkg.Source
701				}
702				if len(pkg.Keywords) > 0 {
703					info.Keywords = append([]string(nil), pkg.Keywords...)
704				}
705				if manifest, err := json.Marshal(pkg); err == nil {
706					info.Manifest = strPtr(string(manifest))
707				}
708			}
709			info.Skills = uniqueStrings(append(info.Skills, scanNamedChildren(root, []string{"skills", ".agents/skills", ".claude/skills"}, "SKILL.md")...))
710			info.Prompts = uniqueStrings(append(info.Prompts, scanNamedChildren(root, []string{"prompts", "library/prompts"}, "")...))
711			info.Templates = uniqueStrings(append(info.Templates, scanNamedChildren(root, []string{"templates", "library/templates"}, "")...))
712		}
713	}
