715	func pluginRootCandidates(workingDir string, name string, entry registry.InstalledEntry) []string {
716		var roots []string
717		if workingDir != "" {
718			roots = append(roots, filepath.Join(workingDir, ".ddx", "plugins", name))
719		}
720		roots = append(roots, registry.ExpandHome(filepath.Join("~", ".ddx", "plugins", name)))
721		for _, f := range entry.Files {
722			expanded := registry.ExpandHome(f)
723			if expanded == "" {
724				continue
725			}
726			roots = append(roots, pluginRootFromRecordedFile(expanded, name))
727		}
728		return uniqueStrings(roots)
729	}
