731	func pluginRootFromRecordedFile(path string, name string) string {
732		cleaned := filepath.Clean(path)
733		if filepath.Base(cleaned) == name {
734			return cleaned
735		}
736		for dir := cleaned; dir != "." && dir != string(filepath.Separator); dir = filepath.Dir(dir) {
737			if filepath.Base(dir) == name && filepath.Base(filepath.Dir(dir)) == "plugins" {
738				return dir
739			}
740			next := filepath.Dir(dir)
741			if next == dir {
742				break
743			}
744		}
745		return cleaned
746	}
