748	func dirSize(root string) int {
749		var total int64
750		_ = filepath.WalkDir(root, func(path string, d fs.DirEntry, err error) error {
751			if err != nil || d.IsDir() {
752				return nil
753			}
754			if info, err := d.Info(); err == nil {
755				total += info.Size()
756			}
757			return nil
758		})
759		const maxInt32 = int64(1<<31 - 1)
760		if total > maxInt32 {
761			return int(maxInt32)
762		}
763		return int(total)
764	}
