766	func scanNamedChildren(root string, relDirs []string, marker string) []string {
767		var out []string
768		for _, rel := range relDirs {
769			base := filepath.Join(root, filepath.FromSlash(rel))
770			entries, err := os.ReadDir(base)
771			if err != nil {
772				continue
773			}
774			for _, entry := range entries {
775				if strings.HasPrefix(entry.Name(), ".") {
776					continue
777				}
778				if marker != "" {
779					if !entry.IsDir() {
780						continue
781					}
782					if _, err := os.Stat(filepath.Join(base, entry.Name(), marker)); err != nil {
783						continue
784					}
785				}
786				out = append(out, entry.Name())
787			}
788		}
789		return out
790	}
