807	func (r *queryResolver) efficacySnapshot(since, until, projectID *string) (efficacySnapshot, error) {
808		projectRoot := r.WorkingDir
809		if projectID != nil && strings.TrimSpace(*projectID) != "" {
810			projectRoot = r.projectRoot(strings.TrimSpace(*projectID))
811		}
812		startedAfter, err := parseOptionalEfficacyTime("since", since)
813		if err != nil {
814			return efficacySnapshot{}, err
815		}
816		startedBefore, err := parseOptionalEfficacyTime("until", until)
817		if err != nil {
818			return efficacySnapshot{}, err
819		}
820		logDir := agent.SessionLogDirForWorkDir(projectRoot)
821		query := agent.SessionIndexQuery{
822			StartedAfter:  startedAfter,
823			StartedBefore: startedBefore,
824		}
825		cacheKey := sessionEfficacyCacheKey(logDir, startedAfter, startedBefore)
826		fingerprint, err := sessionEfficacyIndexFingerprint(logDir, query)
827		if err != nil {
828			return efficacySnapshot{}, err
829		}
830		sessionEfficacyCache.Lock()
831		if sessionEfficacyCache.byQuery == nil {
832			sessionEfficacyCache.byQuery = map[string]sessionEfficacyCacheEntry{}
833		}
834		if cached, ok := sessionEfficacyCache.byQuery[cacheKey]; ok && cached.fingerprint == fingerprint {
835			sessionEfficacyCache.Unlock()
836			return cached.snapshot, nil
837		}
838		sessionEfficacyCache.Unlock()
839	
840		entries, err := agent.ReadSessionIndex(logDir, query)
841		if err != nil {
842			return efficacySnapshot{}, err
843		}
844		snap := buildSessionIndexEfficacySnapshot(entries)
845		sessionEfficacyCache.Lock()
846		sessionEfficacyCache.byQuery[cacheKey] = sessionEfficacyCacheEntry{fingerprint: fingerprint, snapshot: snap}
847		sessionEfficacyCache.Unlock()
848		return snap, nil
849	}
