862	func sessionEfficacyIndexFingerprint(logDir string, query agent.SessionIndexQuery) (string, error) {
863		files, err := agent.SessionIndexShardFiles(logDir, query)
864		if err != nil {
865			return "", err
866		}
867		parts := make([]string, 0, len(files))
868		for _, file := range files {
869			info, err := os.Stat(file)
870			if os.IsNotExist(err) {
871				continue
872			}
873			if err != nil {
874				return "", err
875			}
876			parts = append(parts, fmt.Sprintf("%s:%d:%d", file, info.Size(), info.ModTime().UnixNano()))
877		}
878		return strings.Join(parts, "|"), nil
879	}
