923			attemptDetails[rowKey] = make([]*EfficacyAttempt, 0, len(group))
924			var inputTokens, outputTokens, durations []int
925			var costs []float64
926			var successes int
927			for _, attempt := range group {
928				if attempt.Outcome == "succeeded" {
929					successes++
930				}
931				inputTokens = append(inputTokens, attempt.InputTokens)
932				outputTokens = append(outputTokens, attempt.OutputTokens)
933				durations = append(durations, attempt.DurationMs)
934				if attempt.CostUsd != nil {
935					costs = append(costs, *attempt.CostUsd)
936				}
937				attemptDetails[rowKey] = append(attemptDetails[rowKey], &EfficacyAttempt{
938					BeadID:            attempt.BeadID,
939					Outcome:           attempt.Outcome,
940					DurationMs:        attempt.DurationMs,
941					CostUsd:           attempt.CostUsd,
942					EvidenceBundleURL: attempt.EvidencePath,
943				})
944			}
945			parts := strings.Split(rowKey, "|")
946			row := &EfficacyRow{
947				RowKey:             rowKey,
948				Harness:            parts[0],
949				Provider:           parts[1],
950				Model:              parts[2],
951				Attempts:           len(group),
952				Successes:          successes,
953				SuccessRate:        float64(successes) / float64(len(group)),
954				MedianInputTokens:  medianInt(inputTokens),
955				MedianOutputTokens: medianInt(outputTokens),
956				MedianDurationMs:   medianInt(durations),
957				MedianCostUsd:      medianFloatPtr(costs),
