959			if row.SuccessRate < efficacyWarningFloor {
960				row.Warning = &EfficacyWarning{Kind: "below-adaptive-floor", Threshold: floatPtr(efficacyWarningFloor)}
961			}
962			rows = append(rows, row)
963		}
964		sort.Slice(rows, func(i, j int) bool {
965			if rows[i].SuccessRate != rows[j].SuccessRate {
966				return rows[i].SuccessRate > rows[j].SuccessRate
967			}
968			return rows[i].RowKey < rows[j].RowKey
969		})
970	
971		return efficacySnapshot{rows: rows, attempts: attemptDetails}
