1045	func collectPaletteMatches(query string, workingDir string) []paletteMatch {
1046		var out []paletteMatch
1047		if graph, err := docgraph.BuildGraphWithConfig(workingDir); err == nil {
1048			for _, doc := range graph.AllNodesForOutput() {
1049				if score, ok := paletteScore(query, doc.Path, doc.Title); ok {
1050					out = append(out, paletteMatch{
1051						kind:    "document",
1052						id:      filepath.ToSlash(doc.Path),
1053						title:   doc.Title,
1054						score:   score,
1055						sortKey: "document:" + doc.Path,
1056					})
1057				}
1058			}
1059		}
1060	
1061		store := bead.NewStore(filepath.Join(workingDir, ".ddx"))
1062		if beads, err := store.ReadAll(); err == nil {
1063			for _, b := range beads {
1064				if score, ok := paletteScore(query, b.ID, b.Title); ok {
1065					out = append(out, paletteMatch{kind: "bead", id: b.ID, title: b.Title, score: score, sortKey: "bead:" + b.ID})
1066				}
1067			}
1068		}
1069	
1070		for _, action := range []struct{ id, label string }{
1071			{"drain-queue", "Drain queue"},
1072			{"realign-specs", "Re-align specs"},
1073			{"run-checks", "Run checks"},
1074		} {
1075			if score, ok := paletteScore(query, action.id, action.label); ok {
1076				out = append(out, paletteMatch{kind: "action", id: action.id, title: action.label, score: score, sortKey: "action:" + action.id})
1077			}
1078		}
1079		for _, nav := range []struct{ route, title string }{
1080			{"/beads", "Beads"},
1081			{"/documents", "Documents"},
1082			{"/graph", "Graph"},
1083			{"/workers", "Workers"},
1084			{"/personas", "Personas"},
1085			{"/plugins", "Plugins"},
1086			{"/efficacy", "Efficacy"},
1087		} {
1088			if score, ok := paletteScore(query, nav.route, nav.title); ok {
1089				out = append(out, paletteMatch{kind: "nav", id: nav.route, title: nav.title, score: score, sortKey: "nav:" + nav.route})
1090			}
1091		}
1092		return out
1093	}
1094	
1095	func paletteScore(query string, fields ...string) (int, bool) {
1096		q := strings.ToLower(strings.TrimSpace(query))
1097		if q == "" {
1098			return 0, false
1099		}
1100		terms := strings.Fields(q)
1101		best := 1000
1102		for _, field := range fields {
1103			f := strings.ToLower(field)
1104			if strings.HasPrefix(f, q) {
1105				best = min(best, 0)
1106				continue
1107			}
1108			for _, part := range strings.FieldsFunc(f, func(r rune) bool {
1109				return r == '/' || r == '-' || r == '_' || r == '.' || r == ' ' || r == ':'
1110			}) {
1111				if strings.HasPrefix(part, q) {
1112					best = min(best, 1)
1113				}
1114			}
1115			allTerms := true
1116			for _, term := range terms {
1117				if !strings.Contains(f, term) {
1118					allTerms = false
1119					break
1120				}
1121			}
1122			if allTerms {
1123				best = min(best, 2)
1124			}
1125		}
1126		if best == 1000 {
1127			return 0, false
1128		}
1129		return best, true
1130	}
1131	
1132	func medianInt(values []int) int {
1133		if len(values) == 0 {
1134			return 0
1135		}
1136		sort.Ints(values)
1137		return values[len(values)/2]
1138	}
1139	
1140	func medianFloatPtr(values []float64) *float64 {
1141		if len(values) == 0 {
1142			return nil
1143		}
1144		sort.Float64s(values)
1145		v := values[len(values)/2]
1146		return &v
1147	}
1148	
1149	func firstNonEmpty(values ...string) string {
1150		for _, value := range values {
1151			if strings.TrimSpace(value) != "" {
1152				return strings.TrimSpace(value)
1153			}
1154		}
1155		return ""
1156	}
1157	
1158	func uniqueStrings(values []string) []string {
1159		seen := map[string]bool{}
1160		var out []string
1161		for _, value := range values {
1162			value = strings.TrimSpace(value)
1163			if value == "" || seen[value] {
1164				continue
1165			}
1166			seen[value] = true
1167			out = append(out, value)
1168		}
1169		sort.Strings(out)
1170		return out
1171	}
1172	
1173	func strPtr(v string) *string {
1174		return &v
1175	}
1176	
1177	func floatPtr(v float64) *float64 {
1178		return &v
1179	}
