1181	func slug(v string) string {
1182		v = strings.ToLower(strings.TrimSpace(v))
1183		v = strings.ReplaceAll(v, "_", "-")
1184		v = strings.ReplaceAll(v, " ", "-")
1185		return v
1186	}
